import React, { useState } from 'react';
import { motion } from 'framer-motion';
import './PatientForm.css';

const PatientForm = ({ onSubmit, loading }) => {
  const [formData, setFormData] = useState({
    patient_name: '',
    number_inpatient: '',
    time_in_hospital: '',
    num_medications: '',
    num_procedures: '',
    number_diagnoses: '',
    num_lab_procedures: '',
    number_emergency: '',
    age: '[60-70)',
    insulin: 'Steady'
  });

  const [errors, setErrors] = useState({});

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    // Clear error for this field
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
  };

  const validateForm = () => {
    const newErrors = {};

    if (!formData.patient_name.trim()) {
      newErrors.patient_name = 'Patient name is required';
    }

    Object.keys(formData).forEach(key => {
      if (key !== 'patient_name' && key !== 'age' && key !== 'insulin') {
        if (!formData[key] || formData[key] === '') {
          newErrors[key] = 'This field is required';
        } else if (isNaN(formData[key])) {
          newErrors[key] = 'Must be a valid number';
        }
      }
    });

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (validateForm()) {
      const submitData = {
        ...formData,
        number_inpatient: parseInt(formData.number_inpatient),
        time_in_hospital: parseInt(formData.time_in_hospital),
        num_medications: parseInt(formData.num_medications),
        num_procedures: parseInt(formData.num_procedures),
        number_diagnoses: parseInt(formData.number_diagnoses),
        num_lab_procedures: parseInt(formData.num_lab_procedures),
        number_emergency: parseInt(formData.number_emergency)
      };

      onSubmit(submitData);
    }
  };

  const formFields = [
    { 
      name: 'patient_name', 
      label: 'Patient Name', 
      type: 'text',
      placeholder: 'Enter patient name',
      required: true
    },
    { 
      name: 'number_inpatient', 
      label: 'Number of Inpatient Visits', 
      type: 'number',
      placeholder: '0',
      required: true
    },
    { 
      name: 'time_in_hospital', 
      label: 'Time in Hospital (days)', 
      type: 'number',
      placeholder: '0',
      required: true
    },
    { 
      name: 'num_medications', 
      label: 'Number of Medications', 
      type: 'number',
      placeholder: '0',
      required: true
    },
    { 
      name: 'num_procedures', 
      label: 'Number of Procedures', 
      type: 'number',
      placeholder: '0',
      required: true
    },
    { 
      name: 'number_diagnoses', 
      label: 'Number of Diagnoses', 
      type: 'number',
      placeholder: '0',
      required: true
    },
    { 
      name: 'num_lab_procedures', 
      label: 'Number of Lab Procedures', 
      type: 'number',
      placeholder: '0',
      required: true
    },
    { 
      name: 'number_emergency', 
      label: 'Number of Emergency Visits', 
      type: 'number',
      placeholder: '0',
      required: true
    }
  ];

  return (
    <motion.div
      className="patient-form-container"
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: 0.5 }}
    >
      <div className="form-header">
        <h2>Patient Information</h2>
        <p>Enter patient data to assess readmission risk</p>
      </div>

      <form onSubmit={handleSubmit} className="modern-form">
        <div className="form-grid">
          {formFields.map(field => (
            <div key={field.name} className="form-group">
              <label htmlFor={field.name}>
                {field.label}
                {field.required && <span className="required">*</span>}
              </label>
              <input
                type={field.type}
                id={field.name}
                name={field.name}
                value={formData[field.name]}
                onChange={handleChange}
                placeholder={field.placeholder}
                className={errors[field.name] ? 'error' : ''}
              />
              {errors[field.name] && (
                <span className="error-text">{errors[field.name]}</span>
              )}
            </div>
          ))}

          <div className="form-group">
            <label htmlFor="age">Age Group</label>
            <select
              id="age"
              name="age"
              value={formData.age}
              onChange={handleChange}
              className="modern-select"
            >
              <option value="[0-10)">[0-10)</option>
              <option value="[10-20)">[10-20)</option>
              <option value="[20-30)">[20-30)</option>
              <option value="[30-40)">[30-40)</option>
              <option value="[40-50)">[40-50)</option>
              <option value="[50-60)">[50-60)</option>
              <option value="[60-70)">[60-70)</option>
              <option value="[70-80)">[70-80)</option>
              <option value="[80-90)">[80-90)</option>
              <option value="[90-100)">[90-100)</option>
            </select>
          </div>

          <div className="form-group">
            <label htmlFor="insulin">Insulin Status</label>
            <select
              id="insulin"
              name="insulin"
              value={formData.insulin}
              onChange={handleChange}
              className="modern-select"
            >
              <option value="No">No</option>
              <option value="Steady">Steady</option>
              <option value="Up">Up</option>
              <option value="Down">Down</option>
            </select>
          </div>
        </div>

        <motion.button
          type="submit"
          className="submit-button"
          disabled={loading}
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.98 }}
        >
          {loading ? (
            <div className="loading-spinner"></div>
          ) : (
            '🔍 Assess Risk'
          )}
        </motion.button>
      </form>
    </motion.div>
  );
};

export default PatientForm;
